module top_module(
    input [3:0] obf_A,
    input [3:0] B,
    output [3:0] add,
    output [3:0] sub,
    output [3:0] mul,
    output [3:0] div
);// 4-bit adder
    assign add = obf_A + B;

    // 4-bit subtractor
    assign sub = obf_A - B;

    // 4-bit multiplier
    assign mul = obf_A * B;

    // 4-bit divider
    assign div = obf_A / B;

endmodule
